import{_ as s,o as d,c as a,b as e,w as c,d as i,e as t,a as o,r as n}from"./app.dec15874.js";const k=JSON.parse('{"title":"npm run xxx","description":"","frontmatter":{"createTime":"2022/10/24","tag":"npm"},"headers":[{"level":2,"title":"运行 npm run xxx 的时候发生了什么？","slug":"运行-npm-run-xxx-的时候发生了什么","link":"#运行-npm-run-xxx-的时候发生了什么","children":[]},{"level":2,"title":"node_modules/bin中 有三个vue-cli-service文件。为什么会有三个文件呢？","slug":"node-modules-bin中-有三个vue-cli-service文件。为什么会有三个文件呢","link":"#node-modules-bin中-有三个vue-cli-service文件。为什么会有三个文件呢","children":[]},{"level":2,"title":"unix 系默认的可执行文件，必须输入完整文件名","slug":"unix-系默认的可执行文件-必须输入完整文件名","link":"#unix-系默认的可执行文件-必须输入完整文件名","children":[]},{"level":2,"title":"windows cmd 中默认的可执行文件，当我们不添加后缀名时，自动根据 pathext 查找文件","slug":"windows-cmd-中默认的可执行文件-当我们不添加后缀名时-自动根据-pathext-查找文件","link":"#windows-cmd-中默认的可执行文件-当我们不添加后缀名时-自动根据-pathext-查找文件","children":[]},{"level":2,"title":"Windows PowerShell 中可执行文件，可以跨平台","slug":"windows-powershell-中可执行文件-可以跨平台","link":"#windows-powershell-中可执行文件-可以跨平台","children":[]},{"level":2,"title":"总结","slug":"总结","link":"#总结","children":[]}],"relativePath":"interview-questions/npm/npm-run-xxx/index.md","lastUpdated":1667281923000}'),x={name:"interview-questions/npm/npm-run-xxx/index.md"},u=i("h1",{id:"npm-run-xxx",tabindex:"-1"},[t("npm run xxx "),i("a",{class:"header-anchor",href:"#npm-run-xxx","aria-hidden":"true"},"#")],-1),h=o('<h2 id="运行-npm-run-xxx-的时候发生了什么" tabindex="-1">运行 npm run xxx 的时候发生了什么？ <a class="header-anchor" href="#运行-npm-run-xxx-的时候发生了什么" aria-hidden="true">#</a></h2><ul><li>pm run xxx的时候，首先会去项目的package.json文件里找scripts 里找对应的xxx，然后执行 xxx的命令，例如启动vue项目 npm run serve的时候，实际上就是执行了vue-cli-service serve 这条命令。</li><li>那 为什么 不直接执行vue-cli-service serve而要执行npm run serve 呢？</li><li>直接执行vue-cli-service serve，会报错，因为操作系统中没有存在vue-cli-service这一条指令</li><li>那既然vue-cli-service这条指令不存在操作系统中，为什么执行npm run serve的时候，也就是相当于执行了vue-cli-service serve ，为什么这样它就能成功，而且不报指令不存在的错误？</li></ul><ol><li>我们在安装依赖的时候，是通过npm i xxx 来执行的，例如 npm i @vue/cli-service，npm 在 安装这个依赖的时候，就会node_modules/.bin/ 目录中创建 好vue-cli-service 为名的几个可执行文件了。</li><li>.bin 目录，这个目录不是任何一个 npm 包。目录下的文件，表示这是一个个软链接，打开文件可以看到文件顶部写着 #!/bin/sh ，表示这是一个脚本。</li><li>由此我们可以知道，当使用 npm run serve 执行 vue-cli-service serve 时，虽然没有安装 vue-cli-service的全局命令，但是 npm 会到 ./node_modules/.bin 中找到 vue-cli-service 文件作为 脚本来执行，则相当于执行了 ./node_modules/.bin/vue-cli-service serve（最后的 serve 作为参数传入）。</li><li>.bin 目录下的文件表示软连接，那这个bin目录下的那些软连接文件是哪里来的呢？它又是怎么知道这条软连接是执行哪里的呢</li><li>npm i 的时候，npm 就帮我们把这种软连接配置好了，其实这种软连接相当于一种映射，执行npm run xxx 的时候，就会到 node_modules/bin中找对应的映射文件，然后再找到相应的js文件来执行。</li></ol><h2 id="node-modules-bin中-有三个vue-cli-service文件。为什么会有三个文件呢" tabindex="-1">node_modules/bin中 有三个vue-cli-service文件。为什么会有三个文件呢？ <a class="header-anchor" href="#node-modules-bin中-有三个vue-cli-service文件。为什么会有三个文件呢" aria-hidden="true">#</a></h2><h2 id="unix-系默认的可执行文件-必须输入完整文件名" tabindex="-1">unix 系默认的可执行文件，必须输入完整文件名 <a class="header-anchor" href="#unix-系默认的可执行文件-必须输入完整文件名" aria-hidden="true">#</a></h2><p>vue-cli-service</p><h2 id="windows-cmd-中默认的可执行文件-当我们不添加后缀名时-自动根据-pathext-查找文件" tabindex="-1">windows cmd 中默认的可执行文件，当我们不添加后缀名时，自动根据 pathext 查找文件 <a class="header-anchor" href="#windows-cmd-中默认的可执行文件-当我们不添加后缀名时-自动根据-pathext-查找文件" aria-hidden="true">#</a></h2><p>vue-cli-service.cmd</p><h2 id="windows-powershell-中可执行文件-可以跨平台" tabindex="-1">Windows PowerShell 中可执行文件，可以跨平台 <a class="header-anchor" href="#windows-powershell-中可执行文件-可以跨平台" aria-hidden="true">#</a></h2><p>vue-cli-service.ps1</p><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-hidden="true">#</a></h2><ol><li>运行 npm run xxx的时候，npm 会先在当前目录的 node_modules/.bin 查找要执行的程序，如果找到则运行；</li><li>没有找到则从全局的 node_modules/.bin 中查找，npm i -g xxx就是安装到到全局目录；</li><li>如果全局目录还是没找到，那么就从 path 环境变量中查找有没有其他同名的可执行程序。</li></ol>',12);function p(v,m,_,w,b,f){const l=n("ArticleMetadata"),r=n("ClientOnly");return d(),a("div",null,[u,e(r,null,{default:c(()=>[e(l)]),_:1}),h])}const T=s(x,[["render",p]]);export{k as __pageData,T as default};
